    /// - `GET /<name>/...`: テンプレの静的アセットを配信(ServeDir)。
    ///
    /// `cancel` 発火でサーバを graceful shutdown する。
    pub fn spawn_obs_server(
        &self,
        templates_dir: PathBuf,
        cancel: CancellationToken,
    ) -> Result<tokio::task::JoinHandle<()>, String> {
