+fn inject_template_base(mut html: String, template: &str) -> String {
+    if html.contains("<base ") || html.contains("<base>") {
+        return html;
+    }
+
+    let base = format!(r#"<base href="/{template}/">"#);
+    if let Some(pos) = html.find("<head>") {
+        html.insert_str(pos + "<head>".len(), &base);
+    }
+    html
